var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，他是必不可少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼とともにいることを。","ENG":"that you'll be with him, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和他一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called him to your office. He said he'd be here soon.","TWN":"做好心理準備後，你將他傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"매번 진압작전에, 구조작전까지, 빡세게도 굴려먹으시는군. 몸이 두 개라도 남아나지 않을 지경이야.","JPN":"やっと鎮圧作戦が終わったかと思えば、すぐに救助作戦だからな。毎度毎度こき使いやがって。これでは身体がいくつあっても持たない。","ENG":"Putting me on all kinds of suppression and rescue missions. There's never a break with me.","TWN":"每次鎮壓作戰、救援作戰，對我們也太狠了吧。我身體快吃不消了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 이런 지극히 합법적인 일감들은 우리 같은 범죄자를 불러놓고서 시킬만한 게 아니라고 생각하는데 말이지.","JPN":"しかし、あれもこれも合法な作戦と来た。わざわざ俺達のような犯罪者を呼び寄せてやらせる仕事とは思えないがな。","ENG":"But I don't think it's safe to put criminals like us on legitimate jobs like this.","TWN":"但我覺得這些合法的事情，不太適合交給像我們這種犯罪者去處理吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"설마하니, 날 교화라도 시키고 싶으신 건가?","JPN":"まさか、俺を更生でもさせるつもりか？","ENG":"You're not trying to rehabilitate me, are you?","TWN":"難道說，你要讓我改過自新？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그런 거라면 미안하게 됐어. 난 이제 와서 뜻을 굽힐 생각이 없거든.","JPN":"なら、お生憎様だな。俺に今さらポリシーを曲げるつもりはない。","ENG":"I don't want to disappoint you, but I can't change, even for you. It's too late.","TWN":"很遺憾，我絲毫沒有改變自己這些想法的念頭。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아니, 애초에 타협할 수 없다고 하는 게 맞겠지.","JPN":"いや、そもそも妥協することができないと言った方が正確か。","ENG":"What I want is not negotiable.","TWN":"應該說，從一開始就沒有什麼可談的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"살인자가 반성하고 회개를 해봐야 이미 죽은 사람은 돌아오지 않아.","JPN":"人殺しが罪を悔いたところで、死んだ者が戻ってくることはない。","ENG":"Repenting and changing would never bring back the dead.","TWN":"即使殺人犯反省悔改，已經死去的人也無法復生。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그건 내가 노린 타깃도, 나 자신에게도 마찬가지인 얘기지.","JPN":"それは俺が狙いをつけたターゲットにも、俺自身にも当てはまる話だ。","ENG":"Neither those I killed nor those I lost.","TWN":"我要殺死的目標，還有我自己都是如此。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"번복이나 후회를 할 거라면, 애초에 이 일에 발을 들이지 않았을 거다.","JPN":"過ちを悔いるつもりがあったなら、そもそもこんな仕事に身を投じたりはしない。","ENG":"When I joined this industry, I promised myself that I'd never regret or change my mind.","TWN":"如果怕反悔或後悔，我一開始就不會進入這一行的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"나라도 이 사명을 제대로 끝마치지 않는다면, 지금까지 있었던 민병대의 희생은 아무 의미도 없었던 게 되어버리고 말 테니까.","JPN":"俺だけでもこの使命をきっちり果たさなければ、今までの民兵隊の犠牲はすべて無駄ということになってしまうからな。","ENG":"I must finish what we started as the Militia. I can't let our members' deaths go to waste.","TWN":"如果我不堅持使命，那一直以來民兵隊所做的犧牲都會變得毫無意義。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그렇게 죄인들이 죽고 모두의 복수가 끝났을 때, 민병대란 존재도 이 세상에서 조용히 사라지겠지.","JPN":"そうして罪人達の命が消えてゆき、全員の復讐を終えた時に、民兵隊という存在もこの世から静かに消えてゆくはずだ。","ENG":"When all the criminals die and everyone has gotten their revenge, the Militia will quietly disappear from the world.","TWN":"當所有罪犯都被處決，所有人的復仇都完成後，民兵隊也會從這世界上消失吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그렇게 되기 전까진 우린 그저 복수 밖에 모르는 살아있는 망령일 뿐이야.","JPN":"そうなるまでは、俺達はただ復讐のみに生きる亡霊にすぎん。","ENG":"Until then, we'll continue to fight like the bloodthirsty ghosts we are.","TWN":"直到那一天到來前，我們始終是一群活著的復仇亡靈而已。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러니 우리 후원자께선 망령에게 걸맞은 일을 맡겨달라고.","JPN":"だから、俺達のパトロン様には、亡霊に相応しい仕事を用意してもらいたい。","ENG":"And as our sponsor, you should give us work that befits living ghosts like us.","TWN":"所以請老闆給我們委託適合我們做的事情吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그쪽이 부탁만 한다면 나야 얼마든지 어울려줄 테니까.","JPN":"そちらが頼んでくれさえすれば、俺はいくらでも付き合う覚悟だ。","ENG":"We're available for any work you have, anytime.","TWN":"只要你委託，我一定會盡全力完成。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};